	await service.syncProject({ installationDbId: mockInstallation._id, projectDbId: mockProject._id, projectKey: mockProject.project_key, projectId: mockProject.project_id });

	const searchCall = mockJiraApiService.searchIssues.mock.calls[0]?.[0] as { jql: string } | undefined;
	expect(searchCall?.jql).toMatch(/updated\s*>=\s*"\d{4}-\d{2}-\d{2}"/);

	const threeYearsAgo = new Date(Date.now() - 3 * 365 * 24 * 60 * 60 * 1000);
	const matchedDate = searchCall?.jql?.match(/updated\s*>=\s*"(\d{4}-\d{2}-\d{2})"/)?.[1];
	if (matchedDate) {
		const parsedDate = new Date(matchedDate);
		const diff = Math.abs(parsedDate.getTime() - threeYearsAgo.getTime());
		expect(diff).toBeLessThan(24 * 60 * 60 * 1000);
	}
});

